class Universe {
	static start() {
		Universe.orbCount = rand.next(3, 5);

        Orb.station = new SpaceStation(null, rand.next(Math.TWO_PI), rand.next() > 0.5 ? 1 : -1, 1000);

        var mainPlanet;
		for (var i = 1; i < Universe.orbCount; i++) {
			const planet = new Planet({x: 0, y: 0}, rand.next(Math.TWO_PI), rand.next() > 0.5 ? 1 : -1, i * 5000);

            if (i === 1) {
                mainPlanet = planet;
            }
		}

        Orb.station.parent = mainPlanet;

		Universe.orbCount = (Universe.orbCount + 2) | 0;
	}
}
Universe.orbCount = 0;
class SpaceObject {
	constructor(x, y, spdX, spdY) {
		this.x = x || 0;
		this.y = y || 0;
		this.speedX = spdX || 0;
		this.speedY = spdY || 0;
	}

	updatePosition() {
		this.x += this.speedX;
		this.y += this.speedY;
	}

	isNear(o) {
		return Math.abs(this.x - o.x) < SpaceObject.VISIBLE_DISTANCE && Math.abs(this.y - o.y) < SpaceObject.VISIBLE_DISTANCE;
	}

	onRadar(o) {
		return Math.abs(this.x - o.x) < SpaceObject.RADAR_DISTANCE && Math.abs(this.y - o.y) < SpaceObject.RADAR_DISTANCE;
	}

	getDistance(o) {
		return Math.sqrt( this.getSqrDistance(o) );
	}

	getSqrDistance(o) {
		const dx = this.x - o.x, dy = this.y - o.y;
		return dx * dx + dy * dy;
	}

	getAngle(o) {
		return Math.atan2(o.y - this.y, o.x - this.x);
	}

	get speed() {
		return Math.sqrt(this.sqrSpeed);
	}

	get sqrSpeed() {
		return this.speedX * this.speedX + this.speedY * this.speedY;
	}

	get direction() {
		return Math.atan2(this.speedY, this.speedX);
	}

	get visible() {
		for (var i in Player.list) {
			if (GameBody.list[i].onRadar(this)) {
				return true;
			}
		}

		return false;
	}

}
SpaceObject.VISIBLE_DISTANCE = 1500;
SpaceObject.RADAR_DISTANCE = 3000;
class Orb extends SpaceObject {
	constructor(parent, startAngle, speed, orbitRadius) {
		super();

		//if ( !(this instanceof Star) ) {
			this.parent = parent;
			this.startAngle = startAngle;
			this.orbitRadius = orbitRadius;
			this.angleSpeed = speed / orbitRadius;
		//}

		this.ID = rand.next().toFixed(15);

		Orb.list[this.ID] = this;
	}

	update() {
		this.angle = Math.ang((this.startAngle + this.angleSpeed * Universe.time * 0.025) % Math.TWO_PI);

		this.x = this.parent.x + this.orbitRadius * Math.cos(this.angle);
		this.y = this.parent.y + this.orbitRadius * Math.sin(this.angle);
	}

	static update() {
		Universe.time = Date.now();

		for (var i in Orb.list) {
			Orb.list[i].update();
		}
	}
}
